// // This module selects between two 12-bit inputs, in1 and in2, based on the value of the control signal. When the control signal is 1, the output will be equal to in1, and when the control signal is 0, the output will be equal to in2.
module top_module(in1, in2, control, out);input[11:0] in1,in2;
  output[11:0] out;
  input control;
  assign out = (control) ? in2 : in1;
endmodule
